def load_data():
    with open(FILEPATH, 'r', encoding='utf-8') as f:
        content = f.read()
    prefix = 'window.tracksData = '
    idx = content.find(prefix)
    raw_json = content[idx + len(prefix):]
    suffix = ''
    if raw_json.strip().endswith(';'):
        raw_json = raw_json.strip()[:-1]
        suffix = ';'
    return content[:idx + len(prefix)], json.loads(raw_json), suffix

def save_data(pc, data, suffix):
    with open(FILEPATH, 'w', encoding='utf-8') as f:
        f.write(pc)
        f.write(json.dumps(data, ensure_ascii=False, separators=(',', ':')))
        f.write(suffix)

def apply_fixes(data, lang_key, fixes):
    fixed = 0
    for tk, nc in fixes.items():
        if tk in data.get(lang_key, {}).get('content', {}):
            existing = data[lang_key]['content'][tk]
            nc['title'] = existing.get('title', tk)
            nc['phase'] = existing.get('phase', 1)
            data[lang_key]['content'][tk] = nc
            fixed += 1
            print('  OK %s/%s' % (lang_key, tk))
        else:
            print('  MISS %s/%s' % (lang_key, tk))
    return fixed

if __name__ == '__main__':
    print('Loading tracks_data.js...')
    pc, data, suffix = load_data()
    total = 0
    print('\n--- Fixing PHP ---')
    total += apply_fixes(data, 'php', PHP_FIXES)
    print('\nSaving %d fixes...' % total)
    save_data(pc, data, suffix)
    print('Done!')
